// Get the input item
const item = $input.first().json;

// Build column values object - mapping ALL columns
const columnValues = {};

// Define the columns you want to copy (based on your input data)
const columnsToMap = [
  'color_mkza96dt',    // STATUS
  'date_mkza71cn',     // DATE
  'text_mkzahfaf',     // YACHT
  'text_mkzaqb5z',     // GIVEN NAME
  'text_mkzae4xf',     // SURNAME
  'text_mkzavzhe',     // COMMENTS
  'multiple_person_mm206tfg', // Assignee
  'color_mkzavhpg',    // DOB
  'text_mkzangd3',     // PASSPORT
  'text_mkzavm6e',     // EXPIRY
  'text_mkzabybe',     // VISA REF
  'text_mkza38nk',     // VISA ISSUANCE
  'text_mkzan5vr',     // 1ST ENTRY EXP
  'color_mkzab2es',    // PaidOn
  'color_mkza7ced',    // PaymentRefNumber
  'color_mkza3ajh',    // TransactionNumber
  'color_mkzadx6y',    // JLS Invoices
  'text_mm27qa4j'      // APPLICATION
];

// Process each column
item.column_values.forEach(col => {
  // Only process columns in our list
  if (columnsToMap.includes(col.id)) {
    if (col.value && col.value !== 'null') {
      try {
        const parsedValue = JSON.parse(col.value);

        // Handle different column types
        if (col.type === 'status') {
          // Status columns need label format
          if (col.text) {
            columnValues[col.id] = { label: col.text };
          }
        } else if (col.type === 'date') {
          // Date columns use the parsed value as-is
          columnValues[col.id] = parsedValue;
        } else if (col.type === 'text') {
          // Text columns are simple strings
          columnValues[col.id] = parsedValue;
        } else if (col.type === 'people') {
          // People columns use the parsed value
          columnValues[col.id] = parsedValue;
        } else {
          // Default: use parsed value
          columnValues[col.id] = parsedValue;
        }
      } catch (e) {
        // If parsing fails, use the raw value
        columnValues[col.id] = col.value;
      }
    }
  }
});

return {
  json: {
    name: item.name,
    columnValuesJson: JSON.stringify(columnValues)  // <-- Changed to JSON string
  }
};

